const inputData = $input.first().json;

const sessionId = inputData.sessionId || 
                  inputData.chatId || 
                  `session-${Date.now()}`;

return [{
  json: {
    ...inputData,
    sessionId: sessionId
  }
}];

const body = $input.first().json;

// Simply verify the request has a message
if (!body.chatInput || body.chatInput.trim() === '') {
  throw new Error('Unauthorized: Empty or missing message');
}

// Log valid request
console.log('Valid request from session:', body.sessionId);

return $input.all();

const MAX_REQUESTS = 10; // max per hour
const WINDOW_MS = 3600000; // 1 hour in ms

const body = $input.first().json;
const clientId = body.sessionId || body.authToken || 'anonymous';

// Get existing request log
const store = $getWorkflowStaticData('global');
if (!store.rateLimits) store.rateLimits = {};

const now = Date.now();
const userRequests = store.rateLimits[clientId] || [];

// Keep only requests from last hour
const recentRequests = userRequests.filter(t => now - t < WINDOW_MS);

if (recentRequests.length >= MAX_REQUESTS) {
  throw new Error(`Rate limit exceeded: max ${MAX_REQUESTS} requests/hour`);
}

// Log this request
recentRequests.push(now);
store.rateLimits[clientId] = recentRequests;

return $input.all();
